import os, re

def clean_file(path):
    """Remove read_file line-number prefixes from a file."""
    with open(path) as f:
        content = f.read()
    # Remove patterns like "1|    " or "  1|   " at start of lines
    cleaned = re.sub(r'^\s*\d+\|', '', content, flags=re.MULTILINE)
    if cleaned != content:
        with open(path, 'w') as f:
            f.write(cleaned)
        return True
    return False

for root, dirs, files in os.walk("packages"):
    for fname in files:
        if fname.endswith(('.ts', '.tsx', '.js', '.jsx')):
            fpath = os.path.join(root, fname)
            if clean_file(fpath):
                print(f"Cleaned: {os.path.relpath(fpath)}")

print("Done cleaning all line-number artifacts")
