export interface FilterBadgeProps
  extends Omit<React.HTMLAttributes<HTMLButtonElement>, "onChange">,
    VariantProps<typeof filterBadgeVariants> {
  label: string
  value: string
  isActive?: boolean
  onChange?: (value: string, isActive: boolean) => void
  onRemove?: (value: string) => void
  removable?: boolean
  count?: number
}

export function FilterBadge({
  className,
  variant,
  size,
  label,
  value,
  isActive = false,
  onChange,
  onRemove,
  removable = true,
  count,
  ...props
}: FilterBadgeProps) {
  const handleClick = () => {
    onChange?.(value, !isActive)
  }

  const handleRemove = (e: React.MouseEvent) => {
    e.stopPropagation()
    onRemove?.(value)
  }

  return (
    <button
      onClick={handleClick}
      className={cn(
        filterBadgeVariants({ variant: isActive ? "default" : "outline", size }),
        !isActive && "opacity-70 hover:opacity-100",
        className
      )}
      aria-pressed={isActive}
      {...props}
    >
      <span>{label}</span>
      {count !== undefined && (
        <span className="text-xs opacity-70">({count})</span>
      )}
      {isActive && removable && (
        <span
          onClick={handleRemove}
          className="ml-1 p-0.5 rounded-full hover:bg-white/20 cursor-pointer"
          role="button"
          aria-label={`Remove ${label} filter`}
        >
          <svg
            className="w-3 h-3"
            fill="none"
            stroke="currentColor"
            viewBox="[REDACTED_PHONE]"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M6 18L18 6M6 6l12 12"
            />
          </svg>
        </span>
      )}
    </button>
  )
}

// Filter Badge Group
export interface FilterBadgeGroupProps {
  options: Array<{
    label: string
    value: string
    count?: number
  }>
  activeValues: string[]
  onChange: (values: string[]) => void
  variant?: "default" | "outline" | "muted"
  size?: "sm" | "md" | "lg"
  multiple?: boolean
  className?: string
}

export function FilterBadgeGroup({
  options,
  activeValues,
  onChange,
  variant,
  size,
  multiple = true,
  className,
}: FilterBadgeGroupProps) {
  const handleToggle = (value: string, isActive: boolean) => {
    if (multiple) {
      if (isActive) {
        onChange([...activeValues, value])
      } else {
        onChange(activeValues.filter((v) => v !== value))
      }
    } else {
      onChange(isActive ? [value] : [])
    }
  }

  const handleRemove = (value: string) => {
    onChange(activeValues.filter((v) => v !== value))
  }

  return (
    <div className={cn("flex flex-wrap gap-2", className)} role="group" aria-label="Filter options">
      {options.map((option) => (
        <FilterBadge
          key={option.value}
          label={option.label}
          value={option.value}
          count={option.count}
          isActive={activeValues.includes(option.value)}
          onChange={handleToggle}
          onRemove={handleRemove}
          variant={variant}
          size={size}
        />
      ))}
    </div>
  )
}

